    vowels = {'a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U'}
    s = list(s)
    left, right = 0, len(s) - 1
    while left < right:
        if s[left] in vowels:
            while s[right] not in vowels and left < right:
